#include <iostream>
#include <numeric>
#include <cmath>

class Fraction {
public:
    int numerator;
    int denominator;

    int custom_gcd(int a, int b) const {
        a = std::abs(a);
        b = std::abs(b);
        while (b) {
            a %= b;
            std::swap(a, b);
        }
        return a;
    }

    Fraction(int num = 0, int den = 1) : numerator(num), denominator(den) {
        if (denominator == 0) {
            denominator = 1;
        }
        if (denominator < 0) {
            numerator = -numerator;
            denominator = -denominator;
        }
        simplify();
    }

    void simplify() {
        if (numerator == 0) {
            denominator = 1;
            return;
        }
        int common_divisor = custom_gcd(numerator, denominator);
        numerator /= common_divisor;
        denominator /= common_divisor;
    }

    bool operator==(const Fraction& other) const {
        Fraction f1_simplified = *this;
        Fraction f2_simplified = other;

        f1_simplified.simplify();
        f2_simplified.simplify();

        return (f1_simplified.numerator == f2_simplified.numerator) && (f1_simplified.denominator == f2_simplified.denominator);
    }

    void print() const {
        std::cout << numerator << "/" << denominator;
    }
};

int main() {
    Fraction f1(1, 2);
    Fraction f2(2, 4);
    Fraction f3(1, 3);
    Fraction f4(2, 6);
    Fraction f5(3, 5);
    Fraction f6(0, 5);
    Fraction f7(0, 1);

    std::cout << (f1 == f2 ? "true" : "false") << std::endl;
    std::cout << (f1 == f3 ? "true" : "false") << std::endl;
    std::cout << (f3 == f4 ? "true" : "false") << std::endl;
    std::cout << (f1 == f5 ? "true" : "false") << std::endl;
    std::cout << (f6 == f7 ? "true" : "false") << std::endl;

    return 0;
}
